module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;
    integer i;

    always @(A or B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend or divisor) begin
        remainder <= 0;
        quotient <= 0;

        for (i = 15; i >= 8; i = i - 1) begin
            remainder <= {remainder[14:0], dividend[i]};
            if (remainder >= divisor) begin
                remainder <= remainder - divisor;
                quotient[i] <= 1'b1;
            end
            else begin
                quotient[i] <= 1'b0;
            end
        end

        result <= quotient;
        odd <= remainder;
    end
endmodule
